import json,re
d=json.load(open("/tmp/fullscan.json"))
rows=[]
for p in d["packages"]:
    vs=p.get("vulnerabilities",[])
    if not vs: continue
    name=p["name"]; ver=p["version"]
    for v in vs:
        fi=None
        for r in v.get("reasons",[]):
            m=re.search(r"upgrade to ([^\s]+)",r)
            if m: fi=m.group(1)
        rows.append((name,ver,v["id"],v["severity"],v.get("fix_state","?"),v.get("affected_version_range","?"),fi))
from collections import defaultdict
byp=defaultdict(list)
for r in rows: byp[(r[0],r[1])].append(r)
for (name,ver),rs in sorted(byp.items()):
    print(f"\n### {name}@{ver}")
    for _,_,vid,sev,fs,rng,fi in rs:
        flag = "" if fs=="fixed" else "  <<NOT-FIXED"
        print(f"   {vid:22} {sev:8} fix_state={fs:10} range={rng:28} ->{fi}{flag}")
